@module arrangePage  src=arrangePage.lua  loc=65  sha=accbcb5  mode=chunk
@deps cm, cmgr, chrome, gui, modalHost, facade

# Imports
  @require util = 'util'  @ 12
      @contract  constructs the substack (am local, only av leaves); the renderer is handed av, never am
      @contract  arrange is project-wide — bind() takes no take and never re-keys cm
      @contract  render hooks delegate to arrangeRender; seedCursor drive av directly

# Constructed sub-instances
  @construct am = util.instantiate('arrangeManager')  @ 23
  @construct av = util.instantiate('arrangeView')  @ 24
  @construct ar = util.instantiate('arrangeRender')  @ 25

# Private state
  @state ap = {}  @ 27

# Public API (ap:*)
  -- Page lifecycle — arrange is project-wide, so bind takes no take
  @api ap:bind()  @ 34
      @contract  bind takes no take — arrange is project-wide; coord may call with nil or a take.
  @api ap:unbind()  @ 35
  @api ap:seedCursorFromReaper()  @ 38
      @contract  seeds cursor/focus from am:initialCursor (first selected take, else edit cursor).
  -- Arrange service surface — av passthroughs; newTakeBelow opens a modal in the renderer
  -- Page interface — render delegates to the renderer
  @api ap:renderToolbarBits(ctx)  @ 60
  @api ap:renderBody(_, w, h, dispatch)  @ 61
  @api ap:renderStatusBar(ctx)  @ 62
  @api ap:focusState()  @ 63

# Uses (outbound edges)
  @use call    arrangeRender.focusState  @ 63
  @use call    arrangeRender.newTakeBelow  @ 53
  @use call    arrangeRender.renderBody  @ 61
  @use call    arrangeRender.renderStatusBar  @ 62
  @use call    arrangeRender.renderToolbarBits  @ 60
